    {
      "severity": "blocker",
      "file": "src/app/api/conversations/route.ts",
      "note": "The new code path completely replaces the existing `storage.list()` call, meaning the original listing functionality is silently removed/dead code. The diff claims to add search but actually overwrites behavior."
    },
    {
      "severity": "major",
      "file": "src/app/api/conversations/route.ts",
      "note": "Uses `db.raw()` with raw SQL instead of the repository/storage abstraction layer, violating the modular-monolith convention that Core stays UI-independent and data access goes through defined storage interfaces."
    },
    {
      "severity": "major",
      "file": "src/app/api/conversations/route.ts",
      "note": "No input validation or sanitization on the `q` parameter — no length limits, no character filtering, no max-result pagination, enabling abuse via extremely long strings or wildcard-heavy queries."
    },
    {
      "severity": "major",
      "file": "src/app/api/conversations/route.ts",
      "note": "No tests cover the new search path, the SQL injection vector, or the behavioral change to the GET handler."
    },
    {
      "severity": "minor",
      "file": "src/app/api/conversations/route.ts",
      "note": "The `?? \"\"` default for `q` means an empty search returns all conversations (via `LIKE '%%'`), which may be an unintended full-table scan with no pagination."
